mapper.select:
SELECT * FROM ( SELECT A.*, ROWNUM AS RNUM FROM ( SELECT m.id as MEETING_ID, m.title as TITLE, m.description as DESCRIPTION, m.status as STATUS, m.meeting_date as MEETING_DATE, m.location as LOCATION, m.location_detail as LOCATION_DETAIL, m.created_at as CREATED_AT, (SELECT COUNT(*) FROM woorido.meeting_votes mv JOIN woorido.meeting_vote_records mvr ON mv.id = mvr.meeting_vote_id WHERE mv.meeting_id = m.id AND mvr.choice = 'AGREE') as CONFIRMED_COUNT, (SELECT COUNT(*) FROM woorido.challenge_members cm WHERE cm.challenge_id = m.challenge_id AND cm.privilege_status = 'ACTIVE') as TOTAL_MEMBERS FROM woorido.meetings m WHERE m.challenge_id = #{challengeId}
AND m.status = #{status}
ORDER BY m.meeting_date DESC ) A WHERE ROWNUM <= (#{offset} + #{limit}) ) WHERE RNUM > #{offset}

SELECT COUNT(*)
FROM woorido.meetings
WHERE challenge_id = #{challengeId}

    AND status = #{status}

mapper.update:
UPDATE woorido.meetings
title = #{title}, description = #{description}, location = #{location}, location_detail = #{locationDetail}, meeting_date = #{meetingDate}, updated_at = #{updatedAt}
WHERE id = #{id}

UPDATE woorido.meetings
SET
  status = 'COMPLETED',
  completed_at = #{completedAt},
  updated_at = #{updatedAt}
WHERE id = #{id}

mapper.select:
SELECT COUNT(*)
FROM woorido.meeting_votes mv
JOIN woorido.meeting_vote_records mvr ON mv.id = mvr.meeting_vote_id
WHERE mv.meeting_id = #{meetingId}
  AND mvr.user_id = #{userId}
  AND mvr.choice = 'AGREE'

SELECT COUNT(*)
FROM woorido.meetings
WHERE challenge_id = #{challengeId}
  AND created_by = #{userId}
  AND status = 'COMPLETED'
  AND completed_at IS NOT NULL
  AND completed_at >= #{since}
